import React, { useEffect, useRef, useState } from 'react';
import './App.css';

const STEP_OPTIONS = [1, 5, 10];

export default function App() {
  const [count, setCount] = useState(0);
  const [step, setStep] = useState(1);
  const [autoRunning, setAutoRunning] = useState(false);
  const intervalRef = useRef<number | null>(null);
  const stepRef = useRef(step);

  useEffect(() => {
    stepRef.current = step;
  }, [step]);

  const stopAuto = () => {
    if (intervalRef.current !== null) {
      window.clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setAutoRunning(false);
  };

  useEffect(() => () => stopAuto(), []);

  const inc = () => setCount((current) => current + stepRef.current);
  const dec = () => setCount((current) => Math.max(0, current - stepRef.current));
  const reset = () => {
    stopAuto();
    setCount(0);
  };

  const toggleAuto = () => {
    if (intervalRef.current !== null) {
      stopAuto();
      return;
    }
    setAutoRunning(true);
    setCount((current) => current + stepRef.current);
    intervalRef.current = window.setInterval(() => {
      setCount((current) => current + stepRef.current);
    }, 500);
  };

  const onCounterKeyDown = (event: React.KeyboardEvent<HTMLElement>) => {
    const target = event.target as HTMLElement;
    if (['BUTTON', 'SELECT', 'INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
    if (event.key === 'ArrowUp') inc();
    else if (event.key === 'ArrowDown') dec();
    else if (event.key === 'Home') reset();
    else return;
    event.preventDefault();
  };

  return (
    <main className="main">
      <section className="section">
        <h1>Pressure Counter</h1>
        <div className="counter-control" tabIndex={0} aria-describedby="counter-shortcuts" onKeyDown={onCounterKeyDown}>
          <div id="counter-value" className="value" role="status" aria-live="polite">{count}</div>
          <label className="step-label" htmlFor="step-size">Step size</label>
          <select id="step-size" className="step-select" value={step} onChange={(event) => setStep(Number(event.target.value))}>
            {STEP_OPTIONS.map((option) => <option key={option} value={option}>{option}</option>)}
          </select>
          <p id="counter-shortcuts" className="shortcuts">Focus this card: ArrowUp adds, ArrowDown subtracts, Home resets.</p>
          <div className="actions">
            <button type="button" onClick={dec} disabled={count === 0} aria-label="decrement">−</button>
            <button type="button" onClick={inc} aria-label="increment">+</button>
            <button type="button" onClick={reset} className="ghost" aria-label="reset">Reset</button>
            <button type="button" className="auto-toggle" aria-pressed={autoRunning} onClick={toggleAuto}>{autoRunning ? 'Pause' : 'Start'}</button>
          </div>
        </div>
      </section>
    </main>
  );
}
